{"content":"5033: static bool
5034: verify_gimple_stmt (gimple *stmt)
5035: {
5036:   switch (gimple_code (stmt))
5037:     {
5038:     case GIMPLE_ASSIGN:
5039:       return verify_gimple_assign (as_a <gassign *> (stmt));
5040: 
5041:     case GIMPLE_LABEL:
5042:       return verify_gimple_label (as_a <glabel *> (stmt));
5043: 
5044:     case GIMPLE_CALL:
5045:       return verify_gimple_call (as_a <gcall *> (stmt));
5046: 
5047:     case GIMPLE_COND:
5048:       return verify_gimple_cond (as_a <gcond *> (stmt));
5049: 
5050:     case GIMPLE_GOTO:
5051:       return verify_gimple_goto (as_a <ggoto *> (stmt));
5052: 
5053:     case GIMPLE_SWITCH:
5054:       return verify_gimple_switch (as_a <gswitch *> (stmt));
5055: 
5056:     case GIMPLE_RETURN:
5057:       return verify_gimple_return (as_a <greturn *> (stmt));
5058: 
5059:     case GIMPLE_ASM:
5060:       return false;
5061: 
5062:     case GIMPLE_TRANSACTION:
5063:       return verify_gimple_transaction (as_a <gtransaction *> (stmt));
5064: 
5065:     /* Tuples that do not have tree operands.  */
5066:     case GIMPLE_NOP:
5067:     case GIMPLE_PREDICT:
5068:     case GIMPLE_RESX:
5069:     case GIMPLE_EH_DISPATCH:
5070:     case GIMPLE_EH_MUST_NOT_THROW:
5071:       return false;
5072: 
5073:     CASE_GIMPLE_OMP:
5074:       /* OpenMP directives are validated by the FE and never operated
5075: 	 on by the optimizers.  Furthermore, GIMPLE_OMP_FOR may contain
5076: 	 non-gimple expressions when the main index variable has had
5077: 	 its address taken.  This does not affect the loop itself
5078: 	 because the header of an GIMPLE_OMP_FOR is merely used to determine
5079: 	 how to setup the parallel iteration.  */
5080:       return false;
5081: 
5082:     case GIMPLE_ASSUME:
5083:       return false;
5084: 
5085:     case GIMPLE_DEBUG:
5086:       return verify_gimple_debug (stmt);
5087: 
5088:     default:
5089:       gcc_unreachable ();
5090:     }
5091: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/gcc--96dfb333@baaf9b33ef307e3d2752a94e62274c374e6a5e20/-/blob/gcc/tree-cfg.cc%3FL5033-5090"}

