5244: verify_gimple_in_seq (gimple_seq stmts, bool ice)
5245: {
5246:   timevar_push (TV_TREE_STMT_VERIFY);
5247:   bool res = verify_gimple_in_seq_2 (stmts);
5248:   if (res && ice)
5249:     internal_error ("%<verify_gimple%> failed");
5250:   timevar_pop (TV_TREE_STMT_VERIFY);
5251:   return res;
5252: }
