5254: /* Return true when the T can be shared.  */
5255: 
5256: static bool
5257: tree_node_can_be_shared (tree t)
5258: {
5259:   if (IS_TYPE_OR_DECL_P (t)
5260:       || TREE_CODE (t) == SSA_NAME
5261:       || TREE_CODE (t) == IDENTIFIER_NODE
5262:       || TREE_CODE (t) == CASE_LABEL_EXPR
5263:       || TREE_CODE (t) == OMP_NEXT_VARIANT
5264:       || is_gimple_min_invariant (t))
5265:     return true;
5266: 
5267:   if (t == error_mark_node)
5268:     return true;
5269: 
5270:   return false;
5271: }
