{"content":"5159: static bool
5160: verify_gimple_in_seq_2 (gimple_seq stmts)
5161: {
5162:   gimple_stmt_iterator ittr;
5163:   bool err = false;
5164: 
5165:   for (ittr = gsi_start (stmts); !gsi_end_p (ittr); gsi_next (&ittr))
5166:     {
5167:       gimple *stmt = gsi_stmt (ittr);
5168: 
5169:       switch (gimple_code (stmt))
5170:         {
5171: 	case GIMPLE_BIND:
5172: 	  err |= verify_gimple_in_seq_2 (
5173:                    gimple_bind_body (as_a <gbind *> (stmt)));
5174: 	  break;
5175: 
5176: 	case GIMPLE_TRY:
5177: 	  err |= verify_gimple_in_seq_2 (gimple_try_eval (stmt));
5178: 	  err |= verify_gimple_in_seq_2 (gimple_try_cleanup (stmt));
5179: 	  break;
5180: 
5181: 	case GIMPLE_EH_FILTER:
5182: 	  err |= verify_gimple_in_seq_2 (gimple_eh_filter_failure (stmt));
5183: 	  break;
5184: 
5185: 	case GIMPLE_EH_ELSE:
5186: 	  {
5187: 	    geh_else *eh_else = as_a <geh_else *> (stmt);
5188: 	    err |= verify_gimple_in_seq_2 (gimple_eh_else_n_body (eh_else));
5189: 	    err |= verify_gimple_in_seq_2 (gimple_eh_else_e_body (eh_else));
5190: 	  }
5191: 	  break;
5192: 
5193: 	case GIMPLE_CATCH:
5194: 	  err |= verify_gimple_in_seq_2 (gimple_catch_handler (
5195: 					   as_a <gcatch *> (stmt)));
5196: 	  break;
5197: 
5198: 	case GIMPLE_ASSUME:
5199: 	  err |= verify_gimple_in_seq_2 (gimple_assume_body (stmt));
5200: 	  break;
5201: 
5202: 	case GIMPLE_TRANSACTION:
5203: 	  err |= verify_gimple_transaction (as_a <gtransaction *> (stmt));
5204: 	  break;
5205: 
5206: 	default:
5207: 	  {
5208: 	    bool err2 = verify_gimple_stmt (stmt);
5209: 	    if (err2)
5210: 	      debug_gimple_stmt (stmt);
5211: 	    err |= err2;
5212: 	  }
5213: 	}
5214:     }
5215: 
5216:   return err;
5217: }
