5219: /* Verify the contents of a GIMPLE_TRANSACTION.  Returns true if there
5220:    is a problem, otherwise false.  */
5221: 
5222: static bool
5223: verify_gimple_transaction (gtransaction *stmt)
5224: {
5225:   tree lab;
5226: 
5227:   lab = gimple_transaction_label_norm (stmt);
5228:   if (lab != NULL && TREE_CODE (lab) != LABEL_DECL)
5229:     return true;
5230:   lab = gimple_transaction_label_uninst (stmt);
5231:   if (lab != NULL && TREE_CODE (lab) != LABEL_DECL)
5232:     return true;
5233:   lab = gimple_transaction_label_over (stmt);
5234:   if (lab != NULL && TREE_CODE (lab) != LABEL_DECL)
5235:     return true;
5236: 
5237:   return verify_gimple_in_seq_2 (gimple_transaction_body (stmt));
5238: }
